const items = $input.all();
const seen = new Set();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const filtered = [];

for (const item of items) {
  const d = item.json;
  const title = d.title || d.headline || '';
  const link = d.link || d.url || d.guid || '';
  const pubDate = d.pubDate || d.isoDate || d.date || d.published || '';
  const description = d.contentSnippet || d.content || d.description || d.summary || '';
  const source = d.creator || d.author || d.source || d['dc:creator'] || 'Unknown';

  if (!title) continue;

  const normalizedTitle = title.toLowerCase().trim().replace(/\s+/g, ' ');
  if (seen.has(normalizedTitle)) continue;
  seen.add(normalizedTitle);

  if (pubDate) {
    const articleDate = new Date(pubDate);
    if (!isNaN(articleDate.getTime()) && articleDate < sevenDaysAgo) continue;
  }

  filtered.push({
    json: {
      title: title,
      description: description.substring(0, 500),
      link: link,
      source: source,
      pubDate: pubDate,
      collectedAt: now.toISOString()
    }
  });
}

filtered.sort((a, b) => new Date(b.json.pubDate || 0) - new Date(a.json.pubDate || 0));
const result = filtered.slice(0, 10);

if (result.length === 0) {
  return [{ json: { title: 'لا توجد أخبار جديدة', description: '', link: '', source: '', pubDate: '', collectedAt: now.toISOString(), noNews: true } }];
}
return result;

// تحضير طلب Gemini
const items = $input.all();

return items.map(item => {
  const title = item.json.title || '';
  const desc = item.json.description || '';
  const source = item.json.source || '';

  const body = {
    contents: [{
      parts: [{
        text: 'أنت محلل أخبار ضريبية تركية متخصص. حلل هذا الخبر وقيّم أهميته لشركة Aldewan المتخصصة في الامتثال الضريبي. العنوان: ' + title + '. الوصف: ' + desc + '. المصدر: ' + source + '. أجب بـ JSON فقط: {"isRelevant": true/false, "importance": "عالي/متوسط/منخفض", "summaryAr": "ملخص عربي", "summaryTr": "ملخص تركي", "category": "KDV/SGK/Kurumlar/e-Fatura/Genel", "suggestedTitle": "عنوان عربي جذاب"}'
      }]
    }],
    generationConfig: { temperature: 0.3 }
  };

  return {
    json: {
      ...item.json,
      geminiBody: body
    }
  };
});

// Parse Gemini response and prepare for Google Sheets
const items = $input.all();
const originalItems = $('تحضير طلب Gemini').all();

return items.map((item, index) => {
  const original = originalItems[index]?.json || {};

  let analysis = {};
  try {
    const content = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
    // Clean the response - remove markdown code blocks if present
    const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    analysis = JSON.parse(cleaned);
  } catch (e) {
    analysis = {
      isRelevant: true,
      importance: 'متوسط',
      summaryAr: original.description || '',
      summaryTr: '',
      category: 'Genel',
      suggestedTitle: original.title || ''
    };
  }

  if (!analysis.isRelevant) return null;

  return {
    json: {
      title: original.title || '',
      suggestedTitle: analysis.suggestedTitle || '',
      summaryAr: analysis.summaryAr || '',
      summaryTr: analysis.summaryTr || '',
      category: analysis.category || 'Genel',
      importance: analysis.importance || 'متوسط',
      source: original.source || '',
      sourceUrl: original.link || '',
      pubDate: original.pubDate || '',
      collectedAt: original.collectedAt || new Date().toISOString(),
      approved: '',
      status: 'جديد'
    }
  };
}).filter(item => item !== null);
